-- ============================================================================
-- Quiz Seed: Epistle to the Galatians (Chapters 1–6)
-- 3 difficulties × 6 chapters = 96 total questions
--   kids:   3 per chapter  =  18
--   teens:  5 per chapter  =  30
--   adults: 8 per chapter  =  48
-- ============================================================================

-- ═══ Galatians Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Galatians', 1, 'kids', 1, 'Who wrote the letter to the Galatians?', 'Paul', 'Peter', 'John', 'James', 'a', 'Galatians 1:1 — "Paul, an apostle, (not of men, neither by man, but by Jesus Christ)."'),
('Galatians', 1, 'kids', 2, 'What did Paul say he was amazed about?', 'That the Galatians were turning to a different gospel', 'That they had built a new church', 'That they were growing so fast', 'That they had sent him a gift', 'a', 'Galatians 1:6 — "I marvel that ye are so soon removed from him that called you into the grace of Christ unto another gospel."'),
('Galatians', 1, 'kids', 3, 'Who did Paul say taught him the gospel?', 'Jesus Christ', 'The other apostles', 'His teachers', 'His parents', 'a', 'Galatians 1:12 — "I neither received it of man, neither was I taught it, but by the revelation of Jesus Christ."'),
-- Teens
('Galatians', 1, 'teens', 1, 'What did Paul say should happen to anyone who preaches a different gospel?', 'Let him be accursed (anathema)', 'Let him be forgiven', 'Let him be corrected gently', 'Let him be sent away', 'a', 'Galatians 1:8 — "though we, or an angel from heaven, preach any other gospel… let him be accursed."'),
('Galatians', 1, 'teens', 2, 'What was Paul''s former life in Judaism characterized by?', 'Persecuting the church of God and wasting it', 'Quietly studying the Scriptures', 'Traveling to foreign nations', 'Serving in the temple', 'a', 'Galatians 1:13 — "I persecuted the church of God, and wasted it."'),
('Galatians', 1, 'teens', 3, 'When did God set Paul apart according to this chapter?', 'From his mother''s womb', 'From the day of his baptism', 'From the day he met Jesus on the road', 'From the day he entered the synagogue', 'a', 'Galatians 1:15 — "God, who separated me from my mother''s womb, and called me by his grace."'),
('Galatians', 1, 'teens', 4, 'Where did Paul go after his conversion instead of going to Jerusalem?', 'Arabia, and then back to Damascus', 'Egypt and then Rome', 'Antioch and then Ephesus', 'Tarsus and then Corinth', 'a', 'Galatians 1:17 — "I went into Arabia, and returned again unto Damascus."'),
('Galatians', 1, 'teens', 5, 'Which apostle did Paul visit when he finally went to Jerusalem?', 'Peter (Cephas), and he also saw James the Lord''s brother', 'John and Andrew', 'Matthew and Bartholomew', 'Thomas and Philip', 'a', 'Galatians 1:18-19 — "I went up to Jerusalem to see Peter… But other of the apostles saw I none, save James the Lord''s brother."'),
-- Adults
('Galatians', 1, 'adults', 1, 'How does Paul establish his apostolic authority in the opening verse?', 'By stating his apostleship is not from men nor through man, but through Jesus Christ and God the Father who raised Him', 'By listing the miracles he performed', 'By citing his training under Gamaliel', 'By referencing his letter of recommendation from Jerusalem', 'a', 'Galatians 1:1 — "Paul, an apostle, (not of men, neither by man, but by Jesus Christ, and God the Father, who raised him from the dead)."'),
('Galatians', 1, 'adults', 2, 'What does Paul say Christ gave Himself for?', 'To deliver us from this present evil world, according to the will of God and our Father', 'To establish an earthly kingdom in Israel', 'To abolish all forms of government', 'To give mankind wealth and prosperity', 'a', 'Galatians 1:4 — "Who gave himself for our sins, that he might deliver us from this present evil world, according to the will of God and our Father."'),
('Galatians', 1, 'adults', 3, 'How quickly does Paul say the Galatians were removed from the gospel of grace?', '"So soon" — emphasizing the rapid nature of their departure', 'After many years of faithful service', 'Gradually over a generation', 'Only after Paul left the region', 'a', 'Galatians 1:6 — "I marvel that ye are so soon removed from him that called you into the grace of Christ unto another gospel."'),
('Galatians', 1, 'adults', 4, 'What rhetorical question does Paul ask about seeking to please men?', '"If I yet pleased men, I should not be the servant of Christ"', '"Can a man serve two masters at once?"', '"What profit is there in gaining the whole world?"', '"Who among you is without sin?"', 'a', 'Galatians 1:10 — "for if I yet pleased men, I should not be the servant of Christ."'),
('Galatians', 1, 'adults', 5, 'How does Paul describe his zeal in Judaism compared to his contemporaries?', 'He profited in the Jews'' religion above many his equals, being exceedingly zealous of the traditions of his fathers', 'He was the youngest rabbi ever ordained', 'He had memorized the entire Torah by age twelve', 'He was recognized as the chief Pharisee by the Sanhedrin', 'a', 'Galatians 1:14 — "profited in the Jews'' religion above many my equals in mine own nation, being more exceedingly zealous of the traditions of my fathers."'),
('Galatians', 1, 'adults', 6, 'What was God''s purpose in revealing His Son in Paul?', 'That Paul might preach Him among the heathen (Gentiles)', 'That Paul might reform the Jewish temple system', 'That Paul might write the entire New Testament', 'That Paul might become the high priest of Israel', 'a', 'Galatians 1:16 — "To reveal his Son in me, that I might preach him among the heathen."'),
('Galatians', 1, 'adults', 7, 'How long was it before Paul went up to Jerusalem after his conversion?', 'Three years', 'Forty days', 'Seven years', 'One year', 'a', 'Galatians 1:18 — "Then after three years I went up to Jerusalem to see Peter."'),
('Galatians', 1, 'adults', 8, 'What was the reaction of the churches in Judaea regarding Paul?', 'They glorified God in him, having heard that their former persecutor now preached the faith he once destroyed', 'They were suspicious and refused to meet him', 'They sent a delegation to test his theology', 'They immediately appointed him as their bishop', 'a', 'Galatians 1:23-24 — "He which persecuted us in times past now preacheth the faith which once he destroyed. And they glorified God in me."');

-- ═══ Galatians Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Galatians', 2, 'kids', 1, 'Who did Paul take with him to Jerusalem?', 'Barnabas and Titus', 'Peter and John', 'Timothy and Silas', 'Luke and Mark', 'a', 'Galatians 2:1 — "I went up again to Jerusalem with Barnabas, and took Titus with me also."'),
('Galatians', 2, 'kids', 2, 'What did Paul say we are not saved by?', 'The works of the law', 'Being kind to others', 'Going to church', 'Giving money', 'a', 'Galatians 2:16 — "a man is not justified by the works of the law, but by the faith of Jesus Christ."'),
('Galatians', 2, 'kids', 3, 'Who does Paul say now lives in him?', 'Christ', 'Moses', 'Abraham', 'An angel', 'a', 'Galatians 2:20 — "I am crucified with Christ: nevertheless I live; yet not I, but Christ liveth in me."'),
-- Teens
('Galatians', 2, 'teens', 1, 'Why did Paul rebuke Peter (Cephas) to his face in Antioch?', 'Because Peter withdrew from eating with Gentiles when Jewish believers arrived from James', 'Because Peter denied knowing Christ', 'Because Peter refused to preach to the Gentiles', 'Because Peter was teaching false doctrine', 'a', 'Galatians 2:11-12 — "I withstood him to the face, because he was to be blamed. For before that certain came from James, he did eat with the Gentiles: but when they were come, he withdrew."'),
('Galatians', 2, 'teens', 2, 'What three pillars of the church gave Paul the right hand of fellowship?', 'James, Cephas (Peter), and John', 'Matthew, Mark, and Luke', 'Andrew, Philip, and Thomas', 'Barnabas, Silas, and Timothy', 'a', 'Galatians 2:9 — "James, Cephas, and John, who seemed to be pillars… gave to me and Barnabas the right hands of fellowship."'),
('Galatians', 2, 'teens', 3, 'Was Titus compelled to be circumcised even though he was a Greek?', 'No, he was not compelled', 'Yes, James required it', 'Yes, but only symbolically', 'It is not mentioned', 'a', 'Galatians 2:3 — "But neither Titus, who was with me, being a Greek, was compelled to be circumcised."'),
('Galatians', 2, 'teens', 4, 'What did the Jerusalem apostles ask Paul to remember?', 'The poor, which Paul was also eager to do', 'The temple sacrifices', 'The Sabbath laws', 'The feast of Passover', 'a', 'Galatians 2:10 — "Only they would that we should remember the poor; the same which I also was forward to do."'),
('Galatians', 2, 'teens', 5, 'According to Galatians 2:20, how does Paul now live in the flesh?', 'By the faith of the Son of God, who loved him and gave Himself for him', 'By keeping the law of Moses perfectly', 'By following the traditions of the elders', 'By performing miracles and signs', 'a', 'Galatians 2:20 — "the life which I now live in the flesh I live by the faith of the Son of God, who loved me, and gave himself for me."'),
-- Adults
('Galatians', 2, 'adults', 1, 'How many years after his first visit did Paul go up to Jerusalem again?', 'Fourteen years', 'Seven years', 'Three years', 'Twenty years', 'a', 'Galatians 2:1 — "Then fourteen years after I went up again to Jerusalem."'),
('Galatians', 2, 'adults', 2, 'Why did Paul privately communicate the gospel he preached among the Gentiles to the leaders?', 'Lest by any means he should run, or had run, in vain', 'Because he doubted his own message', 'Because the leaders demanded an accounting', 'Because he needed their financial support', 'a', 'Galatians 2:2 — "lest by any means I should run, or had run, in vain."'),
('Galatians', 2, 'adults', 3, 'Who does Paul describe as "false brethren unawares brought in"?', 'Those who came in privately to spy out the liberty believers had in Christ Jesus, to bring them into bondage', 'Roman spies infiltrating the church', 'Former pagans who had not truly converted', 'Tax collectors working for Rome', 'a', 'Galatians 2:4 — "false brethren unawares brought in, who came in privily to spy out our liberty which we have in Christ Jesus, that they might bring us into bondage."'),
('Galatians', 2, 'adults', 4, 'What does Paul say about those who "seemed to be somewhat" (the pillars)?', 'Whatever they were, it makes no matter — God accepteth no man''s person', 'They were the highest authority and must be obeyed', 'They were less knowledgeable than Paul', 'They had lost their apostolic authority', 'a', 'Galatians 2:6 — "But of these who seemed to be somewhat, (whatsoever they were, it maketh no matter to me: God accepteth no man''s person)."'),
('Galatians', 2, 'adults', 5, 'How does Paul distinguish his ministry from Peter''s?', 'The gospel of the uncircumcision was committed to Paul, as the gospel of the circumcision was to Peter', 'Paul was for the educated and Peter for the uneducated', 'Paul worked in cities while Peter worked in rural areas', 'Paul preached grace while Peter preached law', 'a', 'Galatians 2:7 — "the gospel of the uncircumcision was committed unto me, as the gospel of the circumcision was unto Peter."'),
('Galatians', 2, 'adults', 6, 'What does Paul say Peter''s dissimulation led even Barnabas to do?', 'Barnabas was also carried away with their dissimulation (hypocrisy)', 'Barnabas left the church entirely', 'Barnabas confronted the Jerusalem council', 'Barnabas returned to Cyprus permanently', 'a', 'Galatians 2:13 — "And the other Jews dissembled likewise with him; insomuch that Barnabas also was carried away with their dissimulation."'),
('Galatians', 2, 'adults', 7, 'What logical argument does Paul make in 2:17-18 about being found sinners?', 'If seeking justification by Christ makes us sinners, that does not make Christ a minister of sin — for rebuilding what was destroyed makes one a transgressor', 'If we obey the law we cannot sin', 'If Christ died for all then all are automatically saved', 'If the Gentiles keep the law they become Jews', 'a', 'Galatians 2:17-18 — "is therefore Christ the minister of sin? God forbid. For if I build again the things which I destroyed, I make myself a transgressor."'),
('Galatians', 2, 'adults', 8, 'What does Paul say about the relationship between righteousness and the law?', '"If righteousness come by the law, then Christ is dead in vain"', '"The law and grace work together for righteousness"', '"Righteousness by law was once valid but is now expired"', '"The law prepares us to receive righteousness by works"', 'a', 'Galatians 2:21 — "if righteousness come by the law, then Christ is dead in vain."');

-- ═══ Galatians Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Galatians', 3, 'kids', 1, 'Who does Paul say was a man of faith in the Old Testament?', 'Abraham', 'Moses', 'David', 'Elijah', 'a', 'Galatians 3:6 — "Even as Abraham believed God, and it was accounted to him for righteousness."'),
('Galatians', 3, 'kids', 2, 'Are we all one in Christ Jesus?', 'Yes — there is neither Jew nor Greek, bond nor free, male nor female', 'No, some are more important', 'Only if we follow the law', 'Only in heaven, not on earth', 'a', 'Galatians 3:28 — "There is neither Jew nor Greek… for ye are all one in Christ Jesus."'),
('Galatians', 3, 'kids', 3, 'What did Paul call the Galatians for turning away from faith?', 'Foolish', 'Wicked', 'Lost', 'Lazy', 'a', 'Galatians 3:1 — "O foolish Galatians, who hath bewitched you."'),
-- Teens
('Galatians', 3, 'teens', 1, 'How did Paul say the Galatians received the Spirit?', 'By the hearing of faith, not by the works of the law', 'By being circumcised', 'By performing sacrifices', 'By studying the Torah', 'a', 'Galatians 3:2 — "Received ye the Spirit by the works of the law, or by the hearing of faith?"'),
('Galatians', 3, 'teens', 2, 'What does Paul say the law was until Christ came?', 'A schoolmaster to bring us unto Christ', 'A permanent guide for all believers', 'A set of suggestions', 'An obstacle to faith', 'a', 'Galatians 3:24 — "the law was our schoolmaster to bring us unto Christ, that we might be justified by faith."'),
('Galatians', 3, 'teens', 3, 'How many years before the law was the promise given to Abraham?', 'Four hundred and thirty years', 'Two hundred years', 'One thousand years', 'Forty years', 'a', 'Galatians 3:17 — "the covenant, that was confirmed before of God in Christ, the law, which was four hundred and thirty years after, cannot disannul."'),
('Galatians', 3, 'teens', 4, 'Who are the children of Abraham according to Paul?', 'Those who are of faith', 'Only the biological descendants of Abraham', 'Only those who keep the law', 'Only the twelve tribes of Israel', 'a', 'Galatians 3:7 — "they which are of faith, the same are the children of Abraham."'),
('Galatians', 3, 'teens', 5, 'What curse does Paul say Christ redeemed us from?', 'The curse of the law, being made a curse for us', 'The curse of physical death', 'The curse of poverty', 'The curse placed on Adam''s ground', 'a', 'Galatians 3:13 — "Christ hath redeemed us from the curse of the law, being made a curse for us."'),
-- Adults
('Galatians', 3, 'adults', 1, 'What Old Testament quote does Paul use to prove that God justifies the Gentiles by faith?', '"In thee shall all nations be blessed" (from Genesis 12:3)', '"The Lord is my shepherd" (Psalm 23:1)', '"The just shall live by faith" (Habakkuk 2:4) — though he quotes this too', '"I will make of thee a great nation" (Genesis 12:2)', 'a', 'Galatians 3:8 — "the scripture, foreseeing that God would justify the heathen through faith, preached before the gospel unto Abraham, saying, In thee shall all nations be blessed."'),
('Galatians', 3, 'adults', 2, 'What Deuteronomy passage does Paul quote about those under the law?', '"Cursed is every one that continueth not in all things which are written in the book of the law to do them" (Deut 27:26)', '"Hear, O Israel: The Lord our God is one Lord" (Deut 6:4)', '"Thou shalt love the Lord thy God with all thine heart" (Deut 6:5)', '"Man shall not live by bread alone" (Deut 8:3)', 'a', 'Galatians 3:10 — "Cursed is every one that continueth not in all things which are written in the book of the law to do them."'),
('Galatians', 3, 'adults', 3, 'How was Christ''s hanging on a tree connected to the law''s curse?', 'Deuteronomy 21:23 says "Cursed is every one that hangeth on a tree," and Christ bore this curse for us', 'Trees were sacred in Jewish law', 'The tree symbolized the tree of knowledge in Eden', 'Roman law required execution on trees', 'a', 'Galatians 3:13 — "Christ hath redeemed us from the curse of the law, being made a curse for us: for it is written, Cursed is every one that hangeth on a tree."'),
('Galatians', 3, 'adults', 4, 'What distinction does Paul make about God''s promise using the word "seed" (singular)?', 'The promise was to Abraham''s "seed" (singular, meaning Christ), not "seeds" (plural, meaning many)', 'The word seed refers to the nation of Israel collectively', 'Seed means the church as the new Israel', 'Seed refers only to Isaac, Abraham''s son', 'a', 'Galatians 3:16 — "He saith not, And to seeds, as of many; but as of one, And to thy seed, which is Christ."'),
('Galatians', 3, 'adults', 5, 'Through whom was the law ordained, according to Paul?', 'By angels in the hand of a mediator (Moses)', 'Directly by God without any mediator', 'Through the prophets over many generations', 'Through the high priest Aaron', 'a', 'Galatians 3:19 — "it was ordained by angels in the hand of a mediator."'),
('Galatians', 3, 'adults', 6, 'Is the law against the promises of God, according to Paul?', 'God forbid — if a law could have given life, righteousness would have come by the law', 'Yes, the law contradicts grace entirely', 'Only in certain circumstances', 'The law fulfills the promises', 'a', 'Galatians 3:21 — "Is the law then against the promises of God? God forbid: for if there had been a law given which could have given life, verily righteousness should have been by the law."'),
('Galatians', 3, 'adults', 7, 'What does Paul say the Scripture did before faith came?', 'It concluded all under sin, that the promise by faith of Jesus Christ might be given to them that believe', 'It provided a way of salvation through works', 'It divided humanity into chosen and unchosen', 'It established the priesthood as mediators', 'a', 'Galatians 3:22 — "the scripture hath concluded all under sin, that the promise by faith of Jesus Christ might be given to them that believe."'),
('Galatians', 3, 'adults', 8, 'What does Paul say about the identity of those who have been baptized into Christ?', 'They have put on Christ — neither Jew nor Greek, bond nor free, male nor female, all one in Christ', 'They have become spiritual Jews', 'They have transcended all earthly relationships', 'They no longer have individual identities', 'a', 'Galatians 3:27-28 — "as many of you as have been baptized into Christ have put on Christ. There is neither Jew nor Greek… for ye are all one in Christ Jesus."');

-- ═══ Galatians Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Galatians', 4, 'kids', 1, 'Who did God send to redeem those under the law?', 'His Son, born of a woman', 'An angel from heaven', 'A mighty warrior', 'A wise teacher', 'a', 'Galatians 4:4 — "God sent forth his Son, made of a woman, made under the law."'),
('Galatians', 4, 'kids', 2, 'What does Paul say believers can call God?', 'Abba, Father', 'Master', 'Lord of Hosts', 'The Almighty', 'a', 'Galatians 4:6 — "God hath sent forth the Spirit of his Son into your hearts, crying, Abba, Father."'),
('Galatians', 4, 'kids', 3, 'Paul compared two women from the Bible to two covenants. Who were they?', 'Hagar and Sarah', 'Ruth and Naomi', 'Rachel and Leah', 'Eve and Mary', 'a', 'Galatians 4:22-24 — Abraham had two sons, one by a bondmaid (Hagar) and one by a freewoman (Sarah), which are an allegory of two covenants.'),
-- Teens
('Galatians', 4, 'teens', 1, 'What does Paul say believers are no longer, but instead have become?', 'No longer servants but sons, and heirs of God through Christ', 'No longer sinners but saints by works', 'No longer human but spiritual beings', 'No longer mortal but immortal', 'a', 'Galatians 4:7 — "thou art no more a servant, but a son; and if a son, then an heir of God through Christ."'),
('Galatians', 4, 'teens', 2, 'What does Paul fear about the Galatians in verse 11?', 'That he has laboured upon them in vain', 'That they will be persecuted', 'That they will lose their possessions', 'That they will be exiled', 'a', 'Galatians 4:11 — "I am afraid of you, lest I have bestowed upon you labour in vain."'),
('Galatians', 4, 'teens', 3, 'What does Paul say the Galatians would have done for him when he first preached to them?', 'Plucked out their own eyes and given them to him', 'Built him a house', 'Given him all their money', 'Made him their king', 'a', 'Galatians 4:15 — "if it had been possible, ye would have plucked out your own eyes, and have given them to me."'),
('Galatians', 4, 'teens', 4, 'In Paul''s allegory, what does Hagar represent?', 'Mount Sinai in Arabia, which genders to bondage (the old covenant of law)', 'The promised land of Canaan', 'The new Jerusalem', 'The church at Antioch', 'a', 'Galatians 4:24-25 — "the one from the mount Sinai, which gendereth to bondage, which is Agar. For this Agar is mount Sinai in Arabia."'),
('Galatians', 4, 'teens', 5, 'What does Paul say about the Jerusalem above?', 'She is free and is the mother of us all', 'She is bound by the law of Moses', 'She is reserved only for Israel', 'She has not yet been built', 'a', 'Galatians 4:26 — "But Jerusalem which is above is free, which is the mother of us all."'),
-- Adults
('Galatians', 4, 'adults', 1, 'What does Paul mean by "the fulness of the time" in verse 4?', 'The divinely appointed moment when God sent His Son, born of a woman, born under the law, to redeem those under the law', 'The end of the world', 'The completion of the Old Testament canon', 'The moment the Roman Empire reached full power', 'a', 'Galatians 4:4 — "when the fulness of the time was come, God sent forth his Son, made of a woman, made under the law."'),
('Galatians', 4, 'adults', 2, 'What are the "weak and beggarly elements" Paul warns the Galatians about returning to?', 'The elementary principles of the world — observing days, months, times, and years as religious obligations', 'Pagan idol worship', 'Greek philosophy', 'Roman government service', 'a', 'Galatians 4:9-10 — "how turn ye again to the weak and beggarly elements… Ye observe days, and months, and times, and years."'),
('Galatians', 4, 'adults', 3, 'What physical infirmity does Paul reference as the occasion for first preaching to the Galatians?', 'An infirmity of the flesh, which the Galatians did not despise or reject but received him as an angel of God', 'Blindness from his Damascus road experience', 'A broken leg from being stoned', 'A fever he contracted at sea', 'a', 'Galatians 4:13-14 — "through infirmity of the flesh I preached the gospel unto you at the first. And my temptation which was in my flesh ye despised not, nor rejected."'),
('Galatians', 4, 'adults', 4, 'What does Paul say the false teachers want to do to the Galatians?', 'Exclude them so the Galatians would zealously seek the false teachers instead', 'Force them to pay temple taxes', 'Make them leave their homes', 'Turn them over to the Roman authorities', 'a', 'Galatians 4:17 — "They zealously affect you, but not well; yea, they would exclude you, that ye might affect them."'),
('Galatians', 4, 'adults', 5, 'What does Paul compare his anguish for the Galatians to?', 'Travailing in birth again until Christ be formed in them', 'A shepherd searching for lost sheep', 'A farmer waiting for harvest', 'A soldier preparing for battle', 'a', 'Galatians 4:19 — "My little children, of whom I travail in birth again until Christ be formed in you."'),
('Galatians', 4, 'adults', 6, 'In the Hagar/Sarah allegory, what does Paul say those born after the flesh did to those born after the Spirit?', 'He that was born after the flesh persecuted him that was born after the Spirit', 'They lived in peace together', 'They divided the inheritance equally', 'They both served in the temple', 'a', 'Galatians 4:29 — "as then he that was born after the flesh persecuted him that was born after the Spirit, even so it is now."'),
('Galatians', 4, 'adults', 7, 'What Isaiah prophecy does Paul quote about the barren woman?', '"Rejoice, thou barren that bearest not; break forth and cry, thou that travailest not: for the desolate hath many more children than she which hath an husband" (Isaiah 54:1)', '"A virgin shall conceive and bear a son" (Isaiah 7:14)', '"Unto us a child is born" (Isaiah 9:6)', '"The wilderness shall blossom as the rose" (Isaiah 35:1)', 'a', 'Galatians 4:27 — "Rejoice, thou barren that bearest not; break forth and cry, thou that travailest not."'),
('Galatians', 4, 'adults', 8, 'What does the Scripture say to do with the bondwoman and her son?', '"Cast out the bondwoman and her son: for the son of the bondwoman shall not be heir with the son of the freewoman"', '"Let them dwell together in peace"', '"Give the bondwoman her freedom"', '"Divide the inheritance between them"', 'a', 'Galatians 4:30 — "Cast out the bondwoman and her son: for the son of the bondwoman shall not be heir with the son of the freewoman."');

-- ═══ Galatians Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Galatians', 5, 'kids', 1, 'What does Paul say Christ has made us?', 'Free', 'Rich', 'Powerful', 'Famous', 'a', 'Galatians 5:1 — "Stand fast therefore in the liberty wherewith Christ hath made us free."'),
('Galatians', 5, 'kids', 2, 'What is one fruit of the Spirit Paul lists?', 'Love', 'Anger', 'Jealousy', 'Selfishness', 'a', 'Galatians 5:22 — "the fruit of the Spirit is love, joy, peace, longsuffering, gentleness, goodness, faith."'),
('Galatians', 5, 'kids', 3, 'What does Paul say the whole law is fulfilled in?', '"Thou shalt love thy neighbour as thyself"', '"Keep the Sabbath holy"', '"Do not steal"', '"Honor thy father and mother"', 'a', 'Galatians 5:14 — "all the law is fulfilled in one word, even in this; Thou shalt love thy neighbour as thyself."'),
-- Teens
('Galatians', 5, 'teens', 1, 'What does Paul say about those who seek justification by law?', 'They are fallen from grace', 'They are doing the right thing', 'They are almost saved', 'They are the strongest believers', 'a', 'Galatians 5:4 — "whosoever of you are justified by the law; ye are fallen from grace."'),
('Galatians', 5, 'teens', 2, 'What does Paul say about circumcision in Christ Jesus?', 'Neither circumcision availeth any thing, nor uncircumcision; but faith which worketh by love', 'Circumcision is still required for all believers', 'Only uncircumcision matters now', 'Both are equally valid paths to God', 'a', 'Galatians 5:6 — "in Jesus Christ neither circumcision availeth any thing, nor uncircumcision; but faith which worketh by love."'),
('Galatians', 5, 'teens', 3, 'What metaphor does Paul use about false teaching spreading?', '"A little leaven leaveneth the whole lump"', '"One bad apple spoils the barrel"', '"A spark starts a forest fire"', '"One drop poisons the well"', 'a', 'Galatians 5:9 — "A little leaven leaveneth the whole lump."'),
('Galatians', 5, 'teens', 4, 'What are the flesh and the Spirit described as?', 'Contrary to one another, so you cannot do the things you would', 'Complementary forces working together', 'The same thing viewed differently', 'Temporary and permanent aspects of life', 'a', 'Galatians 5:17 — "the flesh lusteth against the Spirit, and the Spirit against the flesh: and these are contrary the one to the other."'),
('Galatians', 5, 'teens', 5, 'How many fruits of the Spirit are listed in Galatians 5:22-23?', 'Nine: love, joy, peace, longsuffering, gentleness, goodness, faith, meekness, temperance', 'Seven', 'Twelve', 'Five', 'a', 'Galatians 5:22-23 — "love, joy, peace, longsuffering, gentleness, goodness, faith, meekness, temperance."'),
-- Adults
('Galatians', 5, 'adults', 1, 'What does Paul say happens to a person who becomes circumcised for justification?', 'Christ shall profit him nothing, and he is a debtor to do the whole law', 'He gains extra merit with God', 'He fulfills the Abrahamic covenant', 'He shows respect for Jewish heritage', 'a', 'Galatians 5:2-3 — "if ye be circumcised, Christ shall profit you nothing… he is a debtor to do the whole law."'),
('Galatians', 5, 'adults', 2, 'What does Paul say believers through the Spirit wait for?', 'The hope of righteousness by faith', 'The physical return of Christ to Jerusalem', 'The restoration of the temple', 'The millennial kingdom', 'a', 'Galatians 5:5 — "we through the Spirit wait for the hope of righteousness by faith."'),
('Galatians', 5, 'adults', 3, 'What does Paul say freedom in Christ should not be used as?', 'An occasion to the flesh; but by love serve one another', 'A reason to stop attending synagogue', 'A justification for breaking civil laws', 'A basis for spiritual pride', 'a', 'Galatians 5:13 — "use not liberty for an occasion to the flesh; but by love serve one another."'),
('Galatians', 5, 'adults', 4, 'What warning does Paul give about the Galatians biting and devouring one another?', 'Take heed that ye be not consumed one of another', 'You will be excommunicated', 'God will send a famine', 'The Romans will punish you', 'a', 'Galatians 5:15 — "if ye bite and devour one another, take heed that ye be not consumed one of another."'),
('Galatians', 5, 'adults', 5, 'What does Paul say about those who are led by the Spirit?', 'They are not under the law', 'They must still keep all ceremonial laws', 'They will never face temptation', 'They are guaranteed earthly prosperity', 'a', 'Galatians 5:18 — "if ye be led of the Spirit, ye are not under the law."'),
('Galatians', 5, 'adults', 6, 'Which of these is NOT listed among the works of the flesh in Galatians 5:19-21?', 'Slothfulness', 'Adultery', 'Witchcraft', 'Envyings', 'a', 'Galatians 5:19-21 lists adultery, fornication, uncleanness, lasciviousness, idolatry, witchcraft, hatred, variance, emulations, wrath, strife, seditions, heresies, envyings, murders, drunkenness, revellings — slothfulness is not in this list.'),
('Galatians', 5, 'adults', 7, 'What does Paul say about the law in relation to the fruit of the Spirit?', '"Against such there is no law"', '"The law requires all of these"', '"These replace the need for law"', '"The law produces these fruits"', 'a', 'Galatians 5:23 — "against such there is no law."'),
('Galatians', 5, 'adults', 8, 'What does Paul say those who are Christ''s have done?', 'Crucified the flesh with the affections and lusts', 'Memorized the entire Torah', 'Been baptized in the Jordan River', 'Made a pilgrimage to Jerusalem', 'a', 'Galatians 5:24 — "they that are Christ''s have crucified the flesh with the affections and lusts."');

-- ═══ Galatians Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Galatians', 6, 'kids', 1, 'What does Paul say we should not grow tired of doing?', 'Good things (well doing)', 'Eating', 'Sleeping', 'Playing', 'a', 'Galatians 6:9 — "let us not be weary in well doing: for in due season we shall reap, if we faint not."'),
('Galatians', 6, 'kids', 2, 'What does Paul say we should help carry for each other?', 'Burdens', 'Swords', 'Books', 'Food', 'a', 'Galatians 6:2 — "Bear ye one another''s burdens, and so fulfil the law of Christ."'),
('Galatians', 6, 'kids', 3, 'What does Paul say matters most — not circumcision but what?', 'A new creature (creation)', 'Following rules', 'Being rich', 'Being strong', 'a', 'Galatians 6:15 — "in Christ Jesus neither circumcision availeth any thing, nor uncircumcision, but a new creature."'),
-- Teens
('Galatians', 6, 'teens', 1, 'What does Paul say about a person who thinks he is something when he is nothing?', 'He deceiveth himself', 'He is truly great', 'He will be humbled by God', 'He is a good leader', 'a', 'Galatians 6:3 — "if a man think himself to be something, when he is nothing, he deceiveth himself."'),
('Galatians', 6, 'teens', 2, 'What principle of sowing and reaping does Paul teach?', 'Whatsoever a man soweth, that shall he also reap — flesh reaps corruption, Spirit reaps life everlasting', 'Good farmers always get good harvests', 'Hard work guarantees success', 'Money planted grows into more money', 'a', 'Galatians 6:7-8 — "whatsoever a man soweth, that shall he also reap. For he that soweth to his flesh shall of the flesh reap corruption; but he that soweth to the Spirit shall of the Spirit reap life everlasting."'),
('Galatians', 6, 'teens', 3, 'What does Paul say those who are taught in the word should do?', 'Share all good things with him that teaches', 'Keep the knowledge to themselves', 'Only learn from scrolls, not people', 'Test every teacher with signs', 'a', 'Galatians 6:6 — "Let him that is taught in the word communicate unto him that teacheth in all good things."'),
('Galatians', 6, 'teens', 4, 'Why does Paul say certain people want the Galatians to be circumcised?', 'So they can boast in the Galatians'' flesh and avoid persecution for the cross of Christ', 'Because circumcision brings health benefits', 'Because Moses commanded it for all nations', 'Because it shows dedication to God', 'a', 'Galatians 6:12-13 — "they constrain you to be circumcised; only lest they should suffer persecution for the cross of Christ… that they may glory in your flesh."'),
('Galatians', 6, 'teens', 5, 'What does Paul say about restoring someone caught in a fault?', 'Those who are spiritual should restore such a one in the spirit of meekness, considering themselves lest they also be tempted', 'They should be immediately expelled from the church', 'They should be publicly shamed', 'Only apostles can restore fallen believers', 'a', 'Galatians 6:1 — "if a man be overtaken in a fault, ye which are spiritual, restore such an one in the spirit of meekness; considering thyself, lest thou also be tempted."'),
-- Adults
('Galatians', 6, 'adults', 1, 'How does Paul reconcile "bear ye one another''s burdens" (6:2) with "every man shall bear his own burden" (6:5)?', 'The Greek uses different words: "bare" (heavy, crushing loads to share) vs "phortion" (individual responsibility/load); community support and personal accountability coexist', 'Paul contradicts himself', 'Verse 5 is about physical burdens while verse 2 is spiritual', 'Verse 2 applies to leaders and verse 5 to laypeople', 'a', 'Galatians 6:2 uses "bare" (heavy burdens) suggesting shared loads, while 6:5 uses "phortion" (a soldier''s pack) suggesting individual responsibility.'),
('Galatians', 6, 'adults', 2, 'What does Paul say a man should do instead of comparing himself with others?', '"Let every man prove his own work, and then shall he have rejoicing in himself alone, and not in another"', '"Compare yourself only to Christ"', '"Seek the approval of the apostles"', '"Measure your faith by your giving"', 'a', 'Galatians 6:4 — "let every man prove his own work, and then shall he have rejoicing in himself alone, and not in another."'),
('Galatians', 6, 'adults', 3, 'What does Paul mean by "God is not mocked"?', 'God cannot be deceived — the principle of sowing and reaping is an unbreakable divine law', 'God punishes those who laugh at Him', 'God does not tolerate jokes in worship', 'God will destroy mockers immediately', 'a', 'Galatians 6:7 — "Be not deceived; God is not mocked: for whatsoever a man soweth, that shall he also reap."'),
('Galatians', 6, 'adults', 4, 'What does Paul say about doing good to all men?', '"As we have therefore opportunity, let us do good unto all men, especially unto them who are of the household of faith"', '"Only help fellow believers"', '"Help only those who can repay you"', '"Give equally to everyone without distinction"', 'a', 'Galatians 6:10 — "as we have therefore opportunity, let us do good unto all men, especially unto them who are of the household of faith."'),
('Galatians', 6, 'adults', 5, 'What is notable about how Paul closes this letter?', 'He writes the closing in his own hand with "large letters," possibly due to an eye ailment', 'He seals it with his apostolic ring', 'He has Timothy sign as co-author', 'He includes a hymn', 'a', 'Galatians 6:11 — "Ye see how large a letter I have written unto you with mine own hand."'),
('Galatians', 6, 'adults', 6, 'What is the only thing Paul says he will glory (boast) in?', 'The cross of our Lord Jesus Christ, by whom the world is crucified unto him and he unto the world', 'His apostolic authority', 'The number of churches he planted', 'His sufferings for the gospel', 'a', 'Galatians 6:14 — "God forbid that I should glory, save in the cross of our Lord Jesus Christ, by whom the world is crucified unto me, and I unto the world."'),
('Galatians', 6, 'adults', 7, 'What does Paul call the rule of being a new creature in Christ?', 'He says "as many as walk according to this rule, peace be on them, and mercy, and upon the Israel of God"', '"This is the first and greatest commandment"', '"This is the way of righteousness"', '"This is the mark of true discipleship"', 'a', 'Galatians 6:15-16 — "in Christ Jesus neither circumcision availeth any thing… but a new creature. And as many as walk according to this rule, peace be on them… and upon the Israel of God."'),
('Galatians', 6, 'adults', 8, 'What does Paul say about the marks on his body?', '"I bear in my body the marks of the Lord Jesus" — referring to scars from persecution', 'He had tattoos of Christian symbols', 'He bore the stigmata miraculously', 'He had marks from Jewish circumcision', 'a', 'Galatians 6:17 — "I bear in my body the marks of the Lord Jesus."');
